update tours set stops = '[{"title": "Императорский дворец и мост Нидзюбаси", "text": "Начинаем в самом сердце Токио — у Императорского дворца, резиденции императорской семьи. Полюбуемся изящным мостом Нидзюбаси и поговорим об истории императорского дома.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/istoricheskiy-tokio/01.jpg"}, {"title": "Токийский вокзал", "text": "Архитектурный памятник эпохи Мэйдзи: краснокирпичный фасад начала XX века, бережно восстановленный в первоначальном виде.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/istoricheskiy-tokio/02.jpg"}, {"title": "Район Асакуса", "text": "Один из старейших и самых атмосферных уголков города: храм Сэнсо-дзи, торговая улочка Накамисэ и дух старого Эдо.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/istoricheskiy-tokio/03.jpg"}, {"title": "Нихонбаси", "text": "Исторический деловой район — сердце старого Токио и точка отсчёта всех дорог Японии.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/istoricheskiy-tokio/04.jpg"}, {"title": "Квартал Гиндза", "text": "Элегантный квартал — центр моды, культуры и современной жизни мегаполиса.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/istoricheskiy-tokio/05.jpg"}]'::jsonb where slug = 'istoricheskiy-tokio';

update tours set stops = '[{"title": "Одайба", "text": "Радужный мост, Статуя Свободы, побережье Токийского залива и современная архитектура на закате.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/tokio-posle-zakata/01.jpg"}, {"title": "Гиндза", "text": "Современная архитектура, флагманские магазины и исторические универмаги — изысканная вечерняя атмосфера.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/tokio-posle-zakata/02.jpg"}, {"title": "Харадзюку", "text": "Молодёжная мода и знаменитая улица Такэсита-дори.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/tokio-posle-zakata/03.jpg"}, {"title": "Сибуя", "text": "Легендарный перекрёсток Shibuya Crossing, памятник Хатико и смотровая Shibuya Sky (по желанию).", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/tokio-posle-zakata/04.jpg"}, {"title": "Синдзюку", "text": "Небоскрёбы и один из крупнейших вокзалов мира в огнях вечернего города.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/tokio-posle-zakata/05.jpg"}, {"title": "Кабуки-тё и Omoide Yokocho", "text": "Неоновые огни, знаменитый 3D-кот и узкие переулки с крошечными ресторанчиками.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/tokio-posle-zakata/06.jpg"}]'::jsonb where slug = 'tokio-posle-zakata';

update tours set stops = '[{"title": "Minaka Odawara", "text": "Современный комплекс в стиле замкового городка с панорамной террасой и видом на город.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/odavara/01.jpg"}, {"title": "Замок Одавара", "text": "Главная достопримечательность: история клана Ходзё и оборона от Тоётоми Хидэёси.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/odavara/02.jpg"}, {"title": "Музей самурайских доспехов", "text": "Коллекция подлинных самурайских доспехов и оружия.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/odavara/03.jpg"}, {"title": "Святилище Хотоку Ниномия", "text": "Посвящено Ниномии Сонтоку — знаменитому японскому просветителю.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/odavara/04.jpg"}, {"title": "Старинные улочки", "text": "Атмосфера эпохи Эдо и ремесленные лавки.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/odavara/05.jpg"}, {"title": "Гастрономическая Одавара", "text": "Камабоко (рыбные пирожные) и местные деликатесы побережья Тихого океана.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/odavara/06.jpg"}]'::jsonb where slug = 'odavara';

update tours set stops = '[{"title": "Izu Panorama Park и Ao Terrace", "text": "Панорамная канатная дорога, вид на залив Суруга и гору Фудзи.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/01.jpg"}, {"title": "Сюдзэндзи Онсэн", "text": "Старинный онсэн-городок, бамбуковая роща и храм с тысячелетней историей.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/02.jpg"}, {"title": "Гора Омуро", "text": "Идеальный вулканический конус и прогулка по краю кратера.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/03.jpg"}, {"title": "Побережье Дзёгасаки", "text": "Лавовые скалы и подвесной мост над океаном.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/04.jpg"}, {"title": "Водопады Кавадзу", "text": "Семь водопадов среди лесов и скал.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/05.jpg"}, {"title": "Онсэн-гейзер и онсэн-яйца", "text": "Горячие источники, гейзер и яйца, сваренные в природной воде.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/06.jpg"}, {"title": "Мыс Иродзаки", "text": "Самая южная точка полуострова и старинный маяк.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/07.jpg"}, {"title": "Золотая копальня Тои", "text": "Крупнейший золотой слиток Японии — 250 кг.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/idzu/08.jpg"}]'::jsonb where slug = 'idzu';

update tours set stops = '[{"title": "Китагути Хонгу Фудзи Сэнгэн Тайся", "text": "Важнейшее святилище у подножия Фудзи: легенды о горе и синтоистские традиции.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/fudzi/01.jpg"}, {"title": "Осино Хаккай", "text": "Село с восемью хрустальными источниками и водяными мельницами.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/fudzi/02.jpg"}, {"title": "Пагода Тюрэйто", "text": "Одна из самых известных панорам Японии: пагода и Фудзи на фоне сакуры.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/fudzi/03.jpg"}, {"title": "Музей Иттику Куботы", "text": "Древняя техника окрашивания шёлка «цудзигахана».", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/fudzi/04.jpg"}, {"title": "Парк Оиси", "text": "Смотровая площадка на берегу озера Кавагутико с видом на Фудзи.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/fudzi/05.jpg"}]'::jsonb where slug = 'fudzi';

update tours set stops = '[{"title": "Храм Хасэдэра", "text": "Позолоченная статуя 11-головой богини Каннон, фигуры Дзидзо, бамбуковая роща и вид на океан.", "image_query": "Hasedera temple Kamakura"}, {"title": "Великий Будда Камакуры", "text": "Бронзовая статуя Будды XIII века под открытым небом.", "image_query": "Great Buddha Kamakura Daibutsu"}, {"title": "Святилище Дзэниарай Бэнтэн", "text": "Святилище в природной пещере и легенда о финансовой удаче.", "image_query": "Zeniarai Benten shrine Kamakura"}, {"title": "Цуругаока Хатимангу", "text": "Главное святилище города, род Минамото и первый сёгунат.", "image_query": "Tsurugaoka Hachimangu shrine"}, {"title": "Улица Комати-дори", "text": "Торговая улочка со сладостями и сувенирами.", "image_query": "Komachi street Kamakura"}, {"title": "Пляж Юйгахама", "text": "Побережье Камакуры и панорама океана.", "image_query": "Yuigahama beach Kamakura"}]'::jsonb where slug = 'kamakura';

update tours set stops = '[{"title": "Канатная дорога Хаконе", "text": "Вулканические ландшафты, вид на Фудзи и озеро Аси с высоты.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/hakone/01.jpg"}, {"title": "Долина Овакудани", "text": "Фумаролы, сернистые источники и знаменитые чёрные яйца.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/hakone/02.jpg"}, {"title": "Озеро Аси", "text": "Прогулка на стилизованном корабле по кратерному озеру.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/hakone/03.jpg"}, {"title": "Святилище Хаконе", "text": "Святилище VIII века среди вековых криптомерий.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/hakone/04.jpg"}, {"title": "Красные тории на воде", "text": "Знаменитые ворота тории, стоящие прямо в озере.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/hakone/05.jpg"}, {"title": "Старинная дорога Токайдо", "text": "Каменная дорога старше 400 лет в аллее криптомерий.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/hakone/06.jpg"}, {"title": "Самурайская застава Хаконе", "text": "Реконструкция пограничной заставы эпохи Эдо.", "image_url": "https://hovvrqsmqnfvfrfyamtg.supabase.co/storage/v1/object/public/media/tours/hakone/07.jpg"}]'::jsonb where slug = 'hakone';

