update tours set stops = '[{"title": "Нихондайра", "text": "Смотровая площадка с одним из лучших видов на Фудзи, залив Суруга и холмы Сидзуоки.", "image_query": "Nihondaira observation deck Mount Fuji"}, {"title": "Канатная дорога и Кунодзан Тосёгу", "text": "Поездка по канатной дороге к мавзолею сёгуна Токугавы Иэясу.", "image_query": "Kunozan Toshogu shrine Shizuoka"}, {"title": "Археологический комплекс Торо", "text": "Воссозданное поселение периода Яёй под открытым небом.", "image_query": "Toro ruins Yayoi village Shizuoka"}, {"title": "Побережье Михо-но-Мацубара", "text": "Сосновая аллея ЮНЕСКО и знаменитые открыточные виды на Фудзи.", "image_query": "Miho no Matsubara pine grove Fuji"}]'::jsonb where slug = 'shimizu-fuji-svyatyni';

